package main

import (
    "context"
    "fmt"
    "time"
)

func main() {
    // ---- Basic context ----
    ctx := context.Background()

    // ---- Context with timeout ----
    fmt.Println("=== Context with Timeout ===")
    ctxTimeout, cancel := context.WithTimeout(ctx, 100*time.Millisecond)
    defer cancel()

    select {
    case <-time.After(200 * time.Millisecond):
        fmt.Println("Work completed")
    case <-ctxTimeout.Done():
        fmt.Println("Timeout:", ctxTimeout.Err())
    }

    // ---- Context with cancellation ----
    fmt.Println("\n=== Context with Cancellation ===")
    ctxCancel, cancel2 := context.WithCancel(ctx)

    go func() {
        time.Sleep(50 * time.Millisecond)
        cancel2()
    }()

    select {
    case <-time.After(200 * time.Millisecond):
        fmt.Println("Work completed")
    case <-ctxCancel.Done():
        fmt.Println("Cancelled:", ctxCancel.Err())
    }

    // ---- Context with values ----
    fmt.Println("\n=== Context with Values ===")
    ctxValue := context.WithValue(ctx, "key", "value")
    value := ctxValue.Value("key")
    fmt.Println("Value:", value)

    // ---- Context in goroutines ----
    fmt.Println("\n=== Context in Goroutines ===")
    ctxWork, cancel3 := context.WithTimeout(ctx, 200*time.Millisecond)
    defer cancel3()

    go worker(ctxWork, "Worker 1")
    go worker(ctxWork, "Worker 2")

    time.Sleep(300 * time.Millisecond)
    fmt.Println("Main done")
}

func worker(ctx context.Context, name string) {
    for {
        select {
        case <-ctx.Done():
            fmt.Printf("%s: stopped: %v\n", name, ctx.Err())
            return
        default:
            fmt.Printf("%s: working...\n", name)
            time.Sleep(50 * time.Millisecond)
        }
    }
}

