package main

import (
    "context"
    "fmt"
    "time"
)

func main() {
    ctx, cancel := context.WithTimeout(context.Background(), 150*time.Millisecond)
    defer cancel()

    go func() {
        for {
            select {
            case <-ctx.Done():
                fmt.Println("Context cancelled:", ctx.Err())
                return
            default:
                fmt.Println("Working...")
                time.Sleep(50 * time.Millisecond)
            }
        }
    }()

    time.Sleep(200 * time.Millisecond)
    fmt.Println("Main done")
}
